// recover-upload.mjs — upload words that were embedded into the local NDJSON but
// whose shard PUT failed (swallowed by the embedder's catch). Reads gpu_ctxemb.ndjson,
// finds words not in the uploaded set, and ships them as shards continuing the live
// R2 manifest. Pure I/O — no GPU. EDGEWORK_API_TOKEN required.
import fs from 'fs';
import readline from 'readline';

const R2 = (process.env.EDGEWORK_R2_PROXY || 'https://www-edgework-app.edgework.ai/api/v1/r2').replace(/\/$/, '');
const RUN = process.argv.includes('--run-id') ? process.argv[process.argv.indexOf('--run-id') + 1] : 'current';
const DIM = 896, SHARD = 4000;
const TOKEN = process.env.EDGEWORK_API_TOKEN;
const ND = 'gpu_ctxemb.ndjson';
const upath = 'gpu_ctxemb.json.uploaded.json';
if (!TOKEN) { console.error('EDGEWORK_API_TOKEN missing'); process.exit(1); }

const uploaded = new Set(fs.existsSync(upath) ? JSON.parse(fs.readFileSync(upath, 'utf8')) : []);
const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
const putR2 = async (key, body, ct) => {
  // The R2 proxy drops connections intermittently (ECONNRESET) — that's what lost
  // the original ~40k. Retry network errors + 5xx/429 with exponential backoff.
  let lastErr;
  for (let attempt = 0; attempt < 7; attempt++) {
    try {
      const r = await fetch(`${R2}/world-knots/${key}`, { method: 'PUT', headers: { Authorization: `Bearer ${TOKEN}`, 'content-type': ct }, body });
      if (r.ok) return;
      if (r.status >= 500 || r.status === 429) lastErr = new Error('PUT ' + key + ' -> ' + r.status);
      else throw new Error('PUT ' + key + ' -> ' + r.status); // 4xx (auth etc.) — don't retry
    } catch (e) { lastErr = e; }
    await sleep(Math.min(500 * 2 ** attempt, 8000));
  }
  throw lastErr;
};

// continue the live manifest (don't clobber existing shards)
let manifestShards = [], shardSeq = 0;
try {
  const mr = await fetch(`${R2}/world-knots/gpu-embed/${RUN}/manifest.json`, { headers: { Authorization: `Bearer ${TOKEN}` } });
  if (mr.ok) { const m = await mr.json(); manifestShards = Array.isArray(m.shards) ? m.shards : []; shardSeq = manifestShards.length; }
} catch {}
console.error(`continuing from ${shardSeq} shards, ${uploaded.size} uploaded`);

let pending = [];
async function flush(final = false) {
  while (pending.length >= SHARD || (final && pending.length)) {
    const chunk = pending.slice(0, SHARD); pending = pending.slice(chunk.length);
    const key = `gpu-embed/${RUN}/shard-${String(++shardSeq).padStart(4, '0')}.json`;
    const obj = {}; for (const e of chunk) obj[e.w] = e.v;
    await putR2(key, JSON.stringify(obj), 'application/json');
    manifestShards.push(key); chunk.forEach((e) => uploaded.add(e.w));
    fs.writeFileSync(upath, JSON.stringify([...uploaded]));
    await putR2(`gpu-embed/${RUN}/manifest.json`, JSON.stringify({ shards: manifestShards, words: uploaded.size, dim: DIM, updated: Date.now() }), 'application/json');
    console.error(`  uploaded ${key} (${chunk.length}) · ${uploaded.size} total`);
  }
}

let recovered = 0;
const rl = readline.createInterface({ input: fs.createReadStream(ND), crlfDelay: Infinity });
for await (const line of rl) {
  const t = line.indexOf('\t'); if (t < 0) continue;
  const w = line.slice(0, t);
  if (uploaded.has(w)) continue;
  let v; try { v = JSON.parse(line.slice(t + 1)); } catch { continue; }
  if (!Array.isArray(v) || v.length !== DIM) continue;
  pending.push({ w, v }); recovered++;
  if (pending.length >= SHARD) await flush();
}
await flush(true);
console.error(`DONE recovered ${recovered} · uploaded total ${uploaded.size}`);
